{"subagent_type": "general-purpose", "description": "Create Domain layer enums and core classes", "prompt": "Create the following PHP files for the HarborBite project Domain layer. These are pure PHP classes with ZERO Laravel imports — they are the foundation of the hexagonal architecture.

Base path: E:/Hale/Coding/Eaglepoint/Task-40/repo/src

**1. app/Domain/Auth/UserRole.php** — PHP 8.1 backed enum:
```php
<?php

declare(strict_types=1);

namespace App\Domain\Auth;

enum UserRole: string
{
    case Cashier = 'cashier';
    case Kitchen = 'kitchen';
    case Manager = 'manager';
    case Administrator = 'administrator';

    public function label(): string
    {
        return match ($this) {
            self::Cashier => 'Cashier',
            self::Kitchen => 'Kitchen',
            self::Manager => 'Manager',
            self::Administrator => 'Administrator',
        };
    }

    public function canAccessStaffRoutes(): bool
    {
        return true; // All roles are staff
    }

    public function canAccessAdminRoutes(): bool
    {
        return $this === self::Administrator;
    }

    public function canAccessManagerRoutes(): bool
    {
        return in_array($this, [self::Manager, self::Administrator]);
    }
}
```

**2. app/Domain/Auth/StepUpVerifier.php** — Pure PHP manager PIN verification:
```php
<?php

declare(strict_types=1);

namespace App\Domain\Auth;

class StepUpVerifier
{
    /**
     * Verify a manager PIN against a bcrypt hash.
     * Uses password_verify (pure PHP, no Laravel dependency).
     */
    public function verify(string $plainPin, string $hashedPin): bool
    {
        if (empty($plainPin) || empty($hashedPin)) {
            return false;
        }

        return password_verify($plainPin, $hashedPin);
    }

    /**
     * Determine if a given action requires step-up verification.
     */
    public function requiresStepUp(string $action, array $context = []): bool
    {
        return match ($action) {
            'cancel_in_preparation' => true,
            'cancel_served' => true,
            'discount_override' => isset($context['discount_amount']) && $context['discount_amount'] > 20.00,
            'settle_ambiguous' => true,
            default => false,
        };
    }
}
```

**3. app/Domain/Order/OrderStatus.php** — Backed enum with state machine transitions:
```php
<?php

declare(strict_types=1);

namespace App\Domain\Order;

enum OrderStatus: string
{
    case PendingConfirmation = 'pending_confirmation';
    case InPreparation = 'in_preparation';
    case Served = 'served';
    case Settled = 'settled';
    case Canceled = 'canceled';

    /**
     * Returns the valid next statuses from the current status.
     */
    public function transitions(): array
    {
        return match ($this) {
            self::PendingConfirmation => [self::InPreparation, self::Canceled],
            self::InPreparation => [self::Served, self::Canceled],
            self::Served => [self::Settled, self::Canceled],
            self::Settled => [], // Terminal
            self::Canceled => [], // Terminal
        };
    }

    public function canTransitionTo(self $target): bool
    {
        return in_array($target, $this->transitions(), true);
    }

    public function isTerminal(): bool
    {
        return empty($this->transitions());
    }

    public function label(): string
    {
        return match ($this) {
            self::PendingConfirmation => 'Pending Confirmation',
            self::InPreparation => 'In Preparation',
            self::Served => 'Served',
            self::Settled => 'Settled',
            self::Canceled => 'Canceled',
        };
    }

    /**
     * Roles allowed to trigger a transition TO this status.
     * Returns an array of UserRole values.
     */
    public function allowedRoles(): array
    {
        return match ($this) {
            self::InPreparation => ['cashier', 'manager', 'administrator'],
            self::Served => ['kitchen', 'manager', 'administrator'],
            self::Settled => ['cashier', 'manager', 'administrator'],
            self::Canceled => ['cashier', 'manager', 'administrator'], // Further restricted by step-up
            self::PendingConfirmation => [], // Initial state, not transitioned to
        };
    }

    /**
     * Whether canceling FROM this status requires a manager PIN.
     */
    public function requiresStepUpForCancel(): bool
    {
        return match ($this) {
            self::InPreparation => true,
            self::Served => true,
            default => false,
        };
    }
}
```

**4. app/Domain/Order/OrderStateMachine.php**:
```php
<?php

declare(strict_types=1);

namespace App\Domain\Order;

use App\Domain\Order\Exceptions\InvalidTransitionException;
use App\Domain\Order\Exceptions\StaleVersionException;
use App\Domain\Order\Exceptions\KitchenLockException;
use App\Domain\Order\Exceptions\InsufficientRoleException;

class OrderStateMachine
{
    /**
     * Validate and describe a state transition.
     *
     * @param OrderStatus $currentStatus Current order status
     * @param OrderStatus $targetStatus Desired status
     * @param int $currentVersion Current order version in DB
     * @param int $expectedVersion Version the client thinks is current
     * @param string $actorRole Role of the user attempting the transition
     * @param bool $stepUpVerified Whether manager PIN was verified
     *
     * @throws StaleVersionException
     * @throws InvalidTransitionException
     * @throws InsufficientRoleException
     *
     * @return int The new version number
     */
    public function transition(
        OrderStatus $currentStatus,
        OrderStatus $targetStatus,
        int $currentVersion,
        int $expectedVersion,
        string $actorRole,
        bool $stepUpVerified = false,
    ): int {
        // 1. Check version (optimistic concurrency)
        if ($currentVersion !== $expectedVersion) {
            throw new StaleVersionException(
                currentVersion: $currentVersion,
                expectedVersion: $expectedVersion,
                currentStatus: $currentStatus->value,
            );
        }

        // 2. Check if transition is valid
        if (!$currentStatus->canTransitionTo($targetStatus)) {
            throw new InvalidTransitionException(
                from: $currentStatus->value,
                to: $targetStatus->value,
            );
        }

        // 3. Check role authorization
        $allowedRoles = $targetStatus->allowedRoles();
        if (!empty($allowedRoles) && !in_array($actorRole, $allowedRoles, true)) {
            throw new InsufficientRoleException(
                role: $actorRole,
                action: "transition to {$targetStatus->value}",
                requiredRoles: $allowedRoles,
            );
        }

        // 4. Check step-up for cancellation
        if ($targetStatus === OrderStatus::Canceled && $currentStatus->requiresStepUpForCancel()) {
            if (!$stepUpVerified) {
                throw new InsufficientRoleException(
                    role: $actorRole,
                    action: "cancel order in {$currentStatus->value} state",
                    requiredRoles: ['manager', 'administrator'],
                    requiresPin: true,
                );
            }
        }

        // 5. Return incremented version
        return $currentVersion + 1;
    }
}
```

