<?php

declare(strict_types=1);

namespace App\Domain\Search;

class AllergenFilter
{
    /**
     * Map of user-facing allergen names to JSONB attribute keys.
     */
    private const ALLERGEN_MAP = [
        'nuts' => 'contains_nuts',
        'gluten' => 'gluten_free', // Note: this is inverted — if gluten_free is false, item contains gluten
    ];

    /**
     * Build JSONB exclusion conditions for the given allergens.
     *
     * Returns an array of [attribute_key, operator, value] for each allergen
     * that should be used to EXCLUDE items.
     *
     * @param array $allergens e.g. ['nuts', 'gluten']
     * @return array Array of exclusion rules
     */
    public function buildExclusions(array $allergens): array
    {
        $exclusions = [];

        foreach ($allergens as $allergen) {
            $allergen = strtolower(trim($allergen));

            if ($allergen === 'nuts') {
                // Exclude items where contains_nuts = true
                $exclusions[] = [
                    'key' => 'contains_nuts',
                    'exclude_when' => true,
                ];
            } elseif ($allergen === 'gluten') {
                // Exclude items where gluten_free = false (i.e., contains gluten)
                $exclusions[] = [
                    'key' => 'gluten_free',
                    'exclude_when' => false,
                ];
            }
        }

        return $exclusions;
    }

    /**
     * Get available allergen filter options.
     */
    public function availableFilters(): array
    {
        return [
            'nuts' => 'Contains Nuts',
            'gluten' => 'Contains Gluten',
        ];
    }
}
