```php
<?php

declare(strict_types=1);

namespace App\Livewire\Cart;

use App\Domain\Cart\CartValidator;
use App\Domain\Cart\TaxCalculator;
use Illuminate\Support\Facades\DB;
use Livewire\Component;

class CartManager extends Component
{
    public array $cartItems = [];
    public float $subtotal = 0;
    public float $tax = 0;
    public float $total = 0;
    public array $taxBreakdown = [];
    public bool $hasItems = false;
    public array $priceChanges = [];

    protected $listeners = ['add-to-cart' => 'addItem', 'cart-refresh' => '$refresh'];

    public function mount(): void
    {
        $this->loadCart();
    }

    public function addItem(int $itemId): void
    {
        $menuItem = DB::table('menu_items')->where('id', $itemId)->where('is_active', true)->first();

        if (!$menuItem) {
            $this->dispatch('notify', type: 'error', message: 'This item is no longer available.');
            return;
        }

        $cart = $this->getOrCreateCart();

        $existing = DB::table('cart_items')
            ->where('cart_id', $cart->id)
            ->where('menu_item_id', $itemId)
            ->first();

        if ($existing) {
            DB::table('cart_items')
                ->where('id', $existing->id)
                ->update([
                    'quantity' => $existing->quantity + 1,
                    'updated_at' => now(),
                ]);
        } else {
            DB::table('cart_items')->insert([
                'cart_id' => $cart->id,
                'menu_item_id' => $itemId,
                'quantity' => 1,
                'flavor_preference' => null,
                'note' => null,
                'unit_price_snapshot' => $menuItem->price,
                'created_at' => now(),
                'updated_at' => now(),
            ]);
        }

        $this->loadCart();
        $this->dispatch('cart-updated', count: count($this->cartItems));
    }

    public function updateQuantity(int $cartItemId, int $quantity): void
    {
        $validator = new CartValidator();
        $errors = $validator->validateQuantity($quantity);

        if (!empty($errors)) {
            $this->dispatch('notify', type: 'error', message: $errors[0]);
            return;
        }

        DB::table('cart_items')
            ->where('id', $cartItemId)
            ->where('cart_id', $this->getCart()?->id)
            ->update(['quantity' => $quantity, 'updated_at' => now()]);

        $this->loadCart();
        $this->dispatch('cart-updated', count: count($this->cartItems));
    }

    public function updateNote(int $cartItemId, string $note): void
    {
        $validator = new CartValidator();
        $errors = $validator->validateNote($note);

        if (!empty($errors)) {
            $this->dispatch('notify', type: 'error', message: $errors[0]);
            return;
        }

        DB::table('cart_items')
            ->where('id', $cartItemId)
            ->where('cart_id', $this->getCart()?->id)
            ->update(['note' => $note, 'updated_at' => now()]);

        $this->loadCart();
    }

    public function updateFlavor(int $cartItemId, string $flavor): void
    {
        DB::table('cart_items')
            ->where('id', $cartItemId)
            ->where('cart_id', $this->getCart()?->id)
            ->update(['flavor_preference' => $flavor, 'updated_at' => now()]);

        $this->loadCart();
    }

    public function removeItem(int $cartItemId): void
    {
        DB::table('cart_items')
            ->where('id', $cartItemId)
            ->where('cart_id', $this->getCart()?->id)
            ->delete();

        $this->loadCart();
        $this->dispatch('cart-updated', count: count($this->cartItems));
    }

    public function clearCart(): void
    {
        $cart = $this->getCart();
        if ($cart) {
            DB::table('cart_items')->where('cart_id', $cart->id)->delete();
        }

        $this->loadCart();
        $this->dispatch('cart-updated', count: 0);
    }

    private function loadCart(): void
    {
        $cart = $this->getCart();
        $this->priceChanges = [];

        if (!$cart) {
            $this->cartItems = [];
            $this->subtotal = 0;
            $this->tax = 0;
            $this->total = 0;
            $this->taxBreakdown = [];
            $this->hasItems = false;
            return;
        }

        $items = DB::table('cart_items')
            ->join('menu_items', 'cart_items.menu_item_id', '=', 'menu_items.id')
            ->where('cart_items.cart_id', $cart->id)
            ->select([
                'cart_items.id',
                'cart_items.menu_item_id',
                'cart_items.quantity',
                'cart_items.flavor_preference',
                'cart_items.note',
                'cart_items.unit_price_snapshot',
                'menu_items.name',
                'menu_items.price as current_price',
                'menu_items.tax_category',
                'menu_items.sku',
                'menu_items.is_active',
            ])
            ->get();

        $this->cartItems = [];
        $taxItems = [];

        foreach ($items as $item) {
            $priceChanged = abs((float) $item->unit_price_snapshot - (float) $item->current_price) > 0.001;
            if ($priceChanged) {
                $this->priceChanges[$item->id] = [
                    'old' => (float) $item->unit_price_snapshot,
                    'new' => (float) $item->current_price,
                ];
            }

            $this->cartItems[] = [
                'id' => $item->id,
                'menu_item_id' => $item->menu_item_id,
                'name' => $item->name,
                'sku' => $item->sku,
                'quantity' => $item->quantity,
                'unit_price' => (float) $item->unit_price_snapshot,
                'current_price' => (float) $item->current_price,
                'line_total' => round((float) $item->unit_price_snapshot * $item->quantity, 2),
                'flavor_preference' => $item->flavor_preference,
                'note' => $item->note,
                'tax_category' => $item->tax_category,
                'is_active' => (bool) $item->is_active,
                'price_changed' => $priceChanged,
            ];

            $taxItems[] = [
                'name' => $item->name,
                'price' => (float) $item->unit_price_snapshot,
                'quantity' => $item->quantity,
                'tax_category' => $item->tax_category,
            ];
        }

        // Calculate totals
        $this->subtotal = round(array_sum(array_column($this->cartItems, 'line_total')), 2);

        $taxRules = DB::table('tax_rules')
            ->whereDate('effective_from', '<=', now())
            ->where(function ($q) {
                $q->whereNull('effective_to')->orWhereDate('effective_to', '>=', now());
            })
            ->get(['category', 'rate'])
            ->map(fn ($r) => (array) $r)
            ->toArray();

        $calculator = new TaxCalculator($taxRules);
        $this->tax = $calculator->calculateCartTax($taxItems);
        $this->taxBreakdown = $calculator->getBreakdown($taxItems);
        $this->total = round($this->subtotal + $this->tax, 2);
        $this->hasItems = !empty($this->cartItems);
    }

    private function getOrCreateCart(): object
    {
        $sessionId = session()->getId();
        $fingerprintId = request()->attributes->get('device_fingerprint_id');

        $cart = DB::table('carts')->where('session_id', $sessionId)->first();

        if (!$cart) {
            $cartId = DB::table('carts')->insertGetId([
                'session_id' => $sessionId,
                'device_fingerprint_id' => $fingerprintId,
                'created_at' => now(),
                'updated_at' => now(),
            ]);
            $cart = DB::table('carts')->find($cartId);
        }

        return $cart;
    }

    private function getCart(): ?object
    {
        return DB::table('carts')->where('session_id', session()->getId())->first();
    }

    public function render()
    {
        return view('livewire.cart.cart-manager');
    }
}
```

