```php
<?php

declare(strict_types=1);

namespace App\Livewire\Checkout;

use App\Application\Order\CreateOrderUseCase;
use Illuminate\Support\Facades\DB;
use Livewire\Component;

class CheckoutFlow extends Component
{
    public ?array $cartSummary = null;
    public bool $orderPlaced = false;
    public ?int $orderId = null;
    public ?string $orderNumber = null;
    public ?string $errorMessage = null;

    public function mount(): void
    {
        $this->loadCartSummary();
    }

    public function placeOrder(): void
    {
        $this->errorMessage = null;
        $cart = DB::table('carts')->where('session_id', session()->getId())->first();

        if (!$cart) {
            $this->errorMessage = 'Your cart is empty.';
            return;
        }

        try {
            $useCase = new CreateOrderUseCase();
            $order = $useCase->execute((int) $cart->id);

            $this->orderPlaced = true;
            $this->orderId = (int) $order['id'];
            $this->orderNumber = $order['order_number'];

            // Clear cart items after order
            DB::table('cart_items')->where('cart_id', $cart->id)->delete();
            $this->dispatch('cart-updated', count: 0);
        } catch (\Throwable $e) {
            $this->errorMessage = $e->getMessage();
        }
    }

    private function loadCartSummary(): void
    {
        $cart = DB::table('carts')->where('session_id', session()->getId())->first();
        if (!$cart) {
            $this->cartSummary = null;
            return;
        }

        $items = DB::table('cart_items')
            ->join('menu_items', 'cart_items.menu_item_id', '=', 'menu_items.id')
            ->where('cart_items.cart_id', $cart->id)
            ->select(['cart_items.*', 'menu_items.name', 'menu_items.tax_category'])
            ->get();

        if ($items->isEmpty()) {
            $this->cartSummary = null;
            return;
        }

        $subtotal = 0;
        $itemList = [];
        foreach ($items as $item) {
            $lineTotal = round((float) $item->unit_price_snapshot * $item->quantity, 2);
            $subtotal += $lineTotal;
            $itemList[] = [
                'name' => $item->name,
                'quantity' => $item->quantity,
                'unit_price' => (float) $item->unit_price_snapshot,
                'line_total' => $lineTotal,
            ];
        }

        $this->cartSummary = [
            'items' => $itemList,
            'subtotal' => round($subtotal, 2),
            'item_count' => count($itemList),
        ];
    }

    public function render()
    {
        return view('livewire.checkout.checkout-flow');
    }
}
