declare(strict_types=1);

namespace App\Livewire\Checkout;

use App\Application\Order\CreateOrderUseCase;
use App\Domain\Promotion\PromotionEvaluator;
use Illuminate\Support\Facades\DB;
use Livewire\Component;

class CheckoutFlow extends Component
{
    public ?array $cartSummary = null;
    public ?array $appliedPromotion = null;
    public bool $orderPlaced = false;
    public ?int $orderId = null;
    public ?string $orderNumber = null;
    public ?string $errorMessage = null;

    public function mount(): void
    {
        $this->loadCartSummary();
    }

    public function placeOrder(): void
    {
        $this->errorMessage = null;
        $cart = DB::table('carts')->where('session_id', session()->getId())->first();

        if (!$cart) {
            $this->errorMessage = 'Your cart is empty.';
            return;
        }

        try {
            $useCase = new CreateOrderUseCase();
            $order = $useCase->execute((int) $cart->id);
            $orderId = (int) $order['id'];

            // Apply promotion if found
            if ($this->appliedPromotion) {
                $discount = (float) $this->appliedPromotion['discount_amount'];

                DB::table('applied_promotions')->insert([
                    'order_id' => $orderId,
                    'promotion_id' => $this->appliedPromotion['promotion_id'],
                    'discount_amount' => $discount,
                    'description' => $this->appliedPromotion['description'],
                    'created_at' => now(),
                    'updated_at' => now(),
                ]);

                // Update order totals with discount
                $currentOrder = DB::table('orders')->find($orderId);
                $newTotal = round((float) $currentOrder->subtotal + (float) $currentOrder->tax - $discount, 2);
                DB::table('orders')->where('id', $orderId)->update([
                    'discount' => $discount,
                    'total' => max(0, $newTotal),
                    'updated_at' => now(),
                ]);
            }

            $this->orderPlaced = true;
            $this->orderId = $orderId;
            $this->orderNumber = $order['order_number'];

            // Clear cart items after order
            DB::table('cart_items')->where('cart_id', $cart->id)->delete();
            $this->dispatch('cart-updated', count: 0);
        } catch (\Throwable $e) {
            $this->errorMessage = $e->getMessage();
        }
    }

    private function loadCartSummary(): void
    {
        $cart = DB::table('carts')->where('session_id', session()->getId())->first();
        if (!$cart) {
            $this->cartSummary = null;
            return;
        }

        $items = DB::table('cart_items')
            ->join('menu_items', 'cart_items.menu_item_id', '=', 'menu_items.id')
            ->where('cart_items.cart_id', $cart->id)
            ->select(['cart_items.*', 'menu_items.name', 'menu_items.sku', 'menu_items.tax_category'])
            ->get();

        if ($items->isEmpty()) {
            $this->cartSummary = null;
            return;
        }

        $subtotal = 0;
        $itemList = [];
        $promoItems = [];

        foreach ($items as $item) {
            $lineTotal = round((float) $item->unit_price_snapshot * $item->quantity, 2);
            $subtotal += $lineTotal;
            $itemList[] = [
                'name' => $item->name,
                'sku' => $item->sku,
                'quantity' => $item->quantity,
                'unit_price' => (float) $item->unit_price_snapshot,
                'line_total' => $lineTotal,
            ];
            $promoItems[] = [
                'sku' => $item->sku,
                'price' => (float) $item->unit_price_snapshot,
                'quantity' => $item->quantity,
                'name' => $item->name,
            ];
        }

        $subtotal = round($subtotal, 2);

        // Evaluate promotions
        $this->appliedPromotion = null;
        $promotions = DB::table('promotions')
            ->where('is_active', true)
            ->where('starts_at', '<=', now())
            ->where('ends_at', '>=', now())
            ->get()
