```php
<?php

declare(strict_types=1);

namespace App\Application\Payment;

use App\Domain\Payment\HmacSigner;
use App\Domain\Payment\Exceptions\ExpiredNonceException;
use App\Domain\Payment\Exceptions\ReplayedNonceException;
use App\Domain\Payment\Exceptions\TamperedSignatureException;
use Illuminate\Support\Facades\DB;

class ConfirmPaymentUseCase
{
    public function __construct(
        private readonly HmacSigner $signer,
    ) {}

    /**
     * @return array{confirmation_id: int, order_status: string, idempotent: bool}
     */
    public function execute(
        string $reference,
        string $hmacSignature,
        string $nonce,
        string $method,
        int $confirmedBy,
        ?string $notes = null,
    ): array {
        return DB::transaction(function () use ($reference, $hmacSignature, $nonce, $method, $confirmedBy, $notes) {
            $intent = DB::table('payment_intents')
                ->where('reference', $reference)
                ->lockForUpdate()
                ->first();

            if (!$intent) {
                throw new \RuntimeException('Payment intent not found.');
            }

            // Idempotency check — if already confirmed, return existing
            if ($intent->status === 'confirmed') {
                $existingConfirmation = DB::table('payment_confirmations')
                    ->where('payment_intent_id', $intent->id)
                    ->first();

                return [
                    'confirmation_id' => $existingConfirmation ? $existingConfirmation->id : 0,
                    'order_status' => 'settled',
                    'idempotent' => true,
                ];
            }

            if ($intent->status === 'canceled') {
                throw new \RuntimeException('Payment intent was canceled.');
            }

            if ($intent->status === 'failed') {
                throw new \RuntimeException('Payment intent has failed.');
            }

            // Check expiry
            if (now()->gt($intent->expires_at)) {
                DB::table('payment_intents')
                    ->where('id', $intent->id)
                    ->update(['status' => 'failed', 'updated_at' => now()]);

                throw new ExpiredNonceException(config('harborbite.payment.hmac_expiry_seconds', 300));
            }

            // Verify HMAC
            $this->signer->verify(
                $hmacSignature,
                [
                    'reference' => $reference,
                    'amount' => (float) $intent->amount,
                    'order_id' => (int) $intent->order_id,
                ],
                $nonce,
                (int) strtotime($intent->created_at),
            );

            // Mark intent as confirmed
            DB::table('payment_intents')
                ->where('id', $intent->id)
                ->update(['status' => 'confirmed', 'updated_at' => now()]);

            // Create confirmation record
            $confirmationId = DB::table('payment_confirmations')->insertGetId([
                'payment_intent_id' => $intent->id,
                'confirmed_by' => $confirmedBy,
                'method' => $method,
                'notes' => $notes ? encrypt($notes) : null,
                'created_at' => now(),
            ]);

            // Transition order to settled
            $order = DB::table('orders')->find($intent->order_id);
            if ($order && $order->status === 'served') {
                DB::table('orders')->where('id', $order->id)->update([
                    'status' => 'settled',
                    'settled_by' => $confirmedBy,
                    'version' => $order->version + 1,
                    'updated_at' => now(),
                ]);

                DB::table('order_status_logs')->insert([
                    'order_id' => $order->id,
                    'from_status' => $order->status,
                    'to_status' => 'settled',
                    'changed_by' => $confirmedBy,
                    'version_at_change' => $order->version + 1,
                    'metadata' => json_encode(['payment_reference' => $reference, 'method' => $method]),
                    'created_at' => now(),
                ]);
            }

            return [
                'confirmation_id' => $confirmationId,
                'order_status' => 'settled',
                'idempotent' => false,
            ];
        });
    }
}
