  if (!match) return;

  const a = parseInt(match[1]);
  const op = match[2];
  const b = parseInt(match[3]);
  const answer = op === '+' ? a + b : a - b;

  const captchaInput = page.locator('input[placeholder="?"]');
  await captchaInput.fill(answer.toString());
}

